import React, { useState } from "react";
import { Plus, Edit2, Trash2, ArrowUpDown, Image as ImageIcon, X } from "lucide-react";

interface Meal {
  id: number;
  image: string;
  name: string;
  category: string;
  calories: number;
  protein: number;
  carbs: number;
  fat: number;
}

const mockMeals: Meal[] = [
  { id: 1, image: "https://images.unsplash.com/photo-1546069901-ba9599a7e63c?w=100&h=100&fit=crop", name: "Grilled Chicken Salad", category: "Lunch", calories: 380, protein: 42, carbs: 18, fat: 15 },
  { id: 2, image: "https://images.unsplash.com/photo-1525351484163-7529414344d8?w=100&h=100&fit=crop", name: "Protein Pancakes", category: "Breakfast", calories: 320, protein: 28, carbs: 35, fat: 8 }
];

export function NutritionManager() {
  const [meals, setMeals] = useState<Meal[]>(mockMeals);
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const [formData, setFormData] = useState({
    name: "", category: "Lunch", calories: "", protein: "", carbs: "", fat: ""
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsDrawerOpen(false);
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-white">Nutrition & Meals Manager</h1>
          <p className="text-gray-400 mt-1">Manage recipes and meal plans</p>
        </div>
        <button 
          onClick={() => setIsDrawerOpen(true)}
          className="bg-[#39FF14] text-[#121212] px-6 py-3 rounded-lg font-bold hover:bg-[#2EE010] transition-colors flex items-center gap-2"
        >
          <Plus className="w-5 h-5" /> Add New Meal
        </button>
      </div>

      <div className="bg-[#1a1a1a] border border-[#2a2a2a] rounded-xl overflow-hidden">
        <table className="w-full">
          <thead className="bg-[#121212] border-b border-[#2a2a2a]">
            <tr className="text-left text-gray-400 text-sm">
              <th className="p-4">Image</th>
              <th className="p-4">Recipe Name</th>
              <th className="p-4">Category</th>
              <th className="p-4">Calories</th>
              <th className="p-4">Macros</th>
              <th className="p-4 text-center">Actions</th>
            </tr>
          </thead>
          <tbody>
            {meals.map((meal) => (
              <tr key={meal.id} className="border-b border-[#2a2a2a] hover:bg-[#121212]">
                <td className="p-4"><img src={meal.image} className="w-12 h-12 rounded-lg object-cover" /></td>
                <td className="p-4 font-bold text-white">{meal.name}</td>
                <td className="p-4"><span className="px-3 py-1 bg-[#121212] rounded-full text-xs">{meal.category}</span></td>
                <td className="p-4 text-white font-bold">{meal.calories} kcal</td>
                <td className="p-4 text-xs text-gray-400">P: {meal.protein}g C: {meal.carbs}g F: {meal.fat}g</td>
                <td className="p-4 flex justify-center gap-2">
                   <button className="p-2 hover:text-[#39FF14]"><Edit2 size={16}/></button>
                   <button onClick={() => setMeals(meals.filter(m => m.id !== meal.id))} className="p-2 hover:text-red-500"><Trash2 size={16}/></button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Modal Manual (Sustituye a Sheet) */}
      {isDrawerOpen && (
        <div className="fixed inset-0 bg-black/80 z-50 flex justify-end">
          <div className="w-full max-w-md bg-[#1a1a1a] h-full p-8 border-l border-[#2a2a2a] overflow-y-auto">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-bold text-white">Add New Meal</h2>
              <button onClick={() => setIsDrawerOpen(false)}><X color="white" /></button>
            </div>
            <form onSubmit={handleSubmit} className="space-y-4">
              <input 
                placeholder="Recipe Name" 
                className="w-full bg-[#121212] border border-[#2a2a2a] p-3 rounded-lg text-white"
                onChange={(e: React.ChangeEvent<HTMLInputElement>) => setFormData({...formData, name: e.target.value})}
              />
              <select 
                className="w-full bg-[#121212] border border-[#2a2a2a] p-3 rounded-lg text-white"
                onChange={(e: React.ChangeEvent<HTMLSelectElement>) => setFormData({...formData, category: e.target.value})}
              >
                <option value="Breakfast">Breakfast</option>
                <option value="Lunch">Lunch</option>
                <option value="Dinner">Dinner</option>
              </select>
              <input 
                placeholder="Calories" type="number" 
                className="w-full bg-[#121212] border border-[#2a2a2a] p-3 rounded-lg text-white"
                onChange={(e: React.ChangeEvent<HTMLInputElement>) => setFormData({...formData, calories: e.target.value})}
              />
              <button className="w-full bg-[#39FF14] text-black font-bold py-3 rounded-lg mt-4">Save Meal</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
